import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "How much weight should you gain during pregnancy?", a: "Recommended total gain depends on pre-pregnancy BMI and whether you are carrying one baby or multiples. Your clinician can personalize the range for your pregnancy." },
  { q: "How does pre-pregnancy BMI affect weight gain recommendations?", a: "Lower BMI usually has a higher recommended gain range, while higher BMI usually has a lower recommended gain range." },
  { q: "When do you gain the most weight during pregnancy?", a: "Most weight gain usually happens during the second and third trimesters after a smaller first-trimester gain." },
  { q: "Is it dangerous to gain too much weight during pregnancy?", a: "Excessive gain can raise risks for gestational diabetes, high blood pressure, delivery complications, and postpartum weight retention." },
  { q: "How do you lose pregnancy weight after birth?", a: "Gradual weight loss through recovery, balanced nutrition, breastfeeding if applicable, and clinician-approved activity is typically safest." },
];

const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
function category(bmi: number) {
  if (bmi < 18.5) return { name: "Underweight", total: [28, 40], twinTotal: [37, 54], weekly: [1, 1.3] };
  if (bmi < 25) return { name: "Normal", total: [25, 35], twinTotal: [37, 54], weekly: [0.8, 1] };
  if (bmi < 30) return { name: "Overweight", total: [15, 25], twinTotal: [31, 50], weekly: [0.5, 0.7] };
  return { name: "Obese", total: [11, 20], twinTotal: [25, 42], weekly: [0.4, 0.6] };
}

export default function PregnancyWeightGainCalculator() {
  const [preWeight, setPreWeight] = useState(140);
  const [heightIn, setHeightIn] = useState(65);
  const [week, setWeek] = useState(24);
  const [babies, setBabies] = useState(1);
  const [currentGain, setCurrentGain] = useState(15);
  const result = useMemo(() => {
    const bmi = preWeight / (heightIn * heightIn) * 703;
    const base = category(bmi);
    const total = babies > 1 ? base.twinTotal : base.total;
    const first = babies > 1 ? [4, 6] : [1, 4.5];
    const weekly = babies > 1 ? [(total[0] - first[0]) / 27, (total[1] - first[1]) / 27] : base.weekly;
    const expectedMin = week <= 13 ? first[0] * week / 13 : first[0] + (week - 13) * weekly[0];
    const expectedMax = week <= 13 ? first[1] * week / 13 : first[1] + (week - 13) * weekly[1];
    const status = currentGain < expectedMin ? "Below range" : currentGain > expectedMax ? "Above range" : "On track";
    return { bmi, base, total, first, weekly, expectedMin, expectedMax, status };
  }, [preWeight, heightIn, week, babies, currentGain]);
  const table = [
    ["Under 18.5", "Underweight", "28-40 lb", "1-4.5 lb", "1.0-1.3 lb"],
    ["18.5-24.9", "Normal", "25-35 lb", "1-4.5 lb", "0.8-1.0 lb"],
    ["25-29.9", "Overweight", "15-25 lb", "1-4.5 lb", "0.5-0.7 lb"],
    ["30 and over", "Obese", "11-20 lb", "1-4.5 lb", "0.4-0.6 lb"],
  ];
  const weeks = [8, 12, 16, 20, 24, 28, 32, 36, 40].map((w) => ({ w, min: w <= 13 ? result.first[0] * w / 13 : result.first[0] + (w - 13) * result.weekly[0], max: w <= 13 ? result.first[1] * w / 13 : result.first[1] + (w - 13) * result.weekly[1] }));
  return (
    <>
      <SEOHead title="Free Pregnancy Weight Gain Calculator Online - Track Healthy Weight Gain During Pregnancy | CalcHive" description="Free online pregnancy weight gain calculator. Calculate recommended weight gain by trimester based on pre-pregnancy BMI and track whether you are on target instantly. 100% free, no signup required." canonical="/pregnancy-weight-gain-calculator" keywords="free pregnancy weight gain calculator, pregnancy weight calculator free online, how much weight to gain during pregnancy calculator free, trimester weight gain calculator free, healthy pregnancy weight tracker free" category="Health Calculators" breadcrumbName="Free Pregnancy Weight Gain Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-teal-600 dark:text-teal-400 bg-teal-50 dark:bg-teal-950/50 px-3 py-1 rounded-full mb-4 inline-block">Health</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Pregnancy Weight Gain Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Track recommended pregnancy weight gain from pre-pregnancy BMI, current week, and number of babies.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold block mb-2">Pre-pregnancy weight (lb)</label><input type="number" value={preWeight} onChange={(e) => setPreWeight(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Height (in)</label><input type="number" value={heightIn} onChange={(e) => setHeightIn(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Current pregnancy week</label><input type="number" value={week} onChange={(e) => setWeek(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Number of babies</label><select value={babies} onChange={(e) => setBabies(Number(e.target.value))} className={inputClass}><option value={1}>One baby</option><option value={2}>Twins or multiples</option></select></div><div><label className="text-sm font-semibold block mb-2">Current weight gain (lb)</label><input type="number" value={currentGain} onChange={(e) => setCurrentGain(Number(e.target.value))} className={inputClass} /></div></div><div className="bg-gradient-to-br from-teal-500 to-teal-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Current Status</p><p className="text-5xl sm:text-6xl font-black text-white">{result.status}</p></div><div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Pre-pregnancy BMI</p><p className="text-lg font-extrabold">{result.bmi.toFixed(1)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total gain range</p><p className="text-lg font-extrabold">{result.total[0]}-{result.total[1]} lb</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Expected by week {week}</p><p className="text-lg font-extrabold">{result.expectedMin.toFixed(1)}-{result.expectedMax.toFixed(1)} lb</p></div></div></section><MedicalDisclaimer variant="pregnancy" /><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold">How to Calculate Healthy Pregnancy Weight Gain for Free</h2><p className="text-muted-foreground leading-relaxed">This estimate starts with pre-pregnancy BMI, then applies trimester-based weight gain guidance. Always follow your pregnancy care team's advice.</p><h2 className="text-2xl font-bold">How Pre-Pregnancy BMI Affects Recommended Weight Gain</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold mb-3">Recommended Pregnancy Weight Gain by Pre-Pregnancy BMI</caption><thead className="bg-muted/60"><tr>{["Pre-Pregnancy BMI", "BMI Category", "Recommended Total Gain", "First Trimester", "Second and Third Trimester Per Week"].map((h) => <th key={h} className="text-left py-3 px-3">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{table.map((r) => <tr key={r[0]}>{r.map((c) => <td key={c} className="py-2.5 px-3">{c}</td>)}</tr>)}</tbody></table></div><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold mb-3">Week by Week Recommended Weight Gain</caption><thead className="bg-muted/60"><tr><th className="text-left py-3 px-3">Week</th><th className="text-left py-3 px-3">Recommended Range</th></tr></thead><tbody className="divide-y divide-border">{weeks.map((r) => <tr key={r.w}><td className="py-2.5 px-3 font-semibold">{r.w}</td><td className="py-2.5 px-3">{r.min.toFixed(1)}-{r.max.toFixed(1)} lb</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold">Free Trimester Weight Gain Tracker for Every Mom</h2></section>
        <section className="mb-8"><h3 className="text-xl font-bold mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/pregnancy-weight-gain-calculator" headingLevel="h3" /></main>
    </>
  );
}


